# compute longest common contiguous token substring
def longest_common_token_substring(a,b):
    atoks = a.split()
    btoks = b.split()
    n,m = len(atoks), len(btoks)
    dp = [[0]*(m+1) for _ in range(n+1)]
    best = 0
    for i in range(1,n+1):
        for j in range(1,m+1):
            if atoks[i-1]==btoks[j-1]:
                dp[i][j] = dp[i-1][j-1]+1
                if dp[i][j]>best:
                    best = dp[i][j]
            else:
                dp[i][j]=0
    return best

